10	type Item = { type: string };
11	type QuoteStep = { op: "quote"; items: Item[] };
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
13	
14	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
15	
16	const quotePremium = (step: QuoteStep): number => {
17	  const itemsBase = step.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
18	  return itemsBase + PROCESSING_FEE;
19	};
20	
21	export const runScenario = (input: unknown): unknown => {
22	  const scenario = input as Scenario;
23	  return {
24	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
25	  };
