const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumFor(item), 0);

const quotePremium = (step: QuoteStep): number =>
  sumBasePremiums(step.items) + PROCESSING_FEE;
